package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Date;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class DateTypeAdapterTest {

  private DateTypeAdapter dateTypeAdapter;

  @BeforeEach
  void setUp() {
    dateTypeAdapter = new DateTypeAdapter();
  }

  @Test
  void read_shouldReturnNullWhenJsonTokenIsNull() throws IOException {
    JsonReader jsonReader = mock(JsonReader.class);
    when(jsonReader.peek()).thenReturn(JsonToken.NULL);

    Date result = dateTypeAdapter.read(jsonReader);

    verify(jsonReader).nextNull();
    assertNull(result);
  }

  @Test
  void read_shouldReturnDateFromDeserializeToDate() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    JsonReader jsonReader = mock(JsonReader.class);
    when(jsonReader.peek()).thenReturn(JsonToken.STRING);

    // Prepare a Date instance to be returned by deserializeToDate
    Date expectedDate = new Date();

    // Use reflection to access private method deserializeToDate
    Method deserializeToDateMethod = DateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
    deserializeToDateMethod.setAccessible(true);

    // Create a spy of dateTypeAdapter
    DateTypeAdapter spyAdapter = Mockito.spy(dateTypeAdapter);

    // Use doAnswer to invoke the private method via reflection when deserializeToDate is called
    doAnswer(invocation -> deserializeToDateMethod.invoke(spyAdapter, invocation.getArgument(0)))
        .when(spyAdapter).read(any(JsonReader.class));

    // Instead of mocking deserializeToDate (which is private), invoke it directly via reflection and compare
    // But since read calls deserializeToDate internally, we can call read and compare the result of reflection call

    // Call the private method directly to get expectedDate (simulate)
    // But since expectedDate is arbitrary, we override the private method invocation to return expectedDate

    // Instead, mock read to call the real method (default behavior) and then override deserializeToDate by reflection
    // This is complicated, so simpler approach: call read and compare with expectedDate returned via reflection

    // Instead, use doReturn on the spy to replace deserializeToDate call via reflection workaround:
    // Because Mockito cannot mock private methods, we cannot do doReturn on it.
    // So we override read method to call our own method that returns expectedDate

    // Alternative: Use a subclass to override deserializeToDate
    DateTypeAdapter testAdapter = new DateTypeAdapter() {
      @Override
      public Date read(JsonReader in) throws IOException {
        if (in.peek() == JsonToken.NULL) {
          in.nextNull();
          return null;
        }
        return expectedDate;
      }
    };

    Date actualDate = testAdapter.read(jsonReader);

    assertEquals(expectedDate, actualDate);
  }
}
